blocks.body:
{
    "level": "A2–B1",
    "intro": "W tym temacie poznasz <strong>różnice między każdym, każdym i wszystkimi</strong> - trzy sposoby powiedzenia „każdy” lub „wszyscy”.",
    "rules": [
        {
            "label": "KAŻDY",
            "color": "emerald",
            "text": "<strong>Każdy</strong> - każdy z osobna (indywidualnie):",
            "example": "Każdy uczeń ma książkę. (każdy inny)"
        },
        {
            "label": "KAŻDY",
            "color": "blue",
            "text": "<strong>Każdy</strong> – każdy bez wyjątku (grupa):",
            "example": "Każdy uczeń zdał. (wszyscy jako grupa)"
        },
        {
            "label": "ALL",
            "color": "amber",
            "text": "<strong>Wszyscy</strong> – wszyscy razem (ogólnie):",
            "example": "Wszyscy uczniowie są tutaj. (wszystko razem)"
        }
    ]
}

{
    "title": "1. Główne różnice",
    "intro": "Główne cechy każdego, każdego i wszystkich:",
    "rows": [
        {
            "en": "każdy",
            "ua": "każdy osobno",
            "note": "+ rzeczownik/czasownik w liczbie pojedynczej. Indywidualnie."
        },
        {
            "en": "każdy",
            "ua": "wszyscy bez wyjątku",
            "note": "+ rzeczownik/czasownik w liczbie pojedynczej. Jako grupa."
        },
        {
            "en": "wszyscy",
            "ua": "wszyscy razem",
            "note": "+ rzeczownik/czasownik w liczbie mnogiej. Ogólność."
        }
    ],
    "warning": "📌 Każdy/każdy + liczba pojedyncza. Wszystko + liczba mnoga."
}

{
    "title": "2. KAŻDY – każdy osobno",
    "sections": [
        {
            "label": "Każdy = indywidualnie",
            "color": "emerald",
            "description": "<strong>Każdy</strong> oznacza „każdy z osobna” – skup się na indywidualności, na każdym elemencie z osobna.",
            "examples": [
                {
                    "en": "Każdy uczeń ma swoją książkę.",
                    "ua": "Кожен студент має книгу (свою окрему)."
                },
                {
                    "en": "Each person is different.",
                    "ua": "Кожна людина різна (окремо)."
                },
                {
                    "en": "I gave each child a toy.",
                    "ua": "Я дав кожній дитині іграшку (окремо кожній)."
                }
            ]
        },
        {
            "label": "Each + singular",
            "color": "sky",
            "description": "<strong>Każdy</strong> zawsze z <strong>rzeczownikiem i czasownikiem w liczbie pojedynczej</strong>.",
            "examples": [
                {
                    "en": "Każdy uczeń ma... (✓)",
                    "ua": "ma - liczba pojedyncza"
                },
                {
                    "en": "Każdy uczeń ma... (✗)",
                    "ua": "BŁĄD - trzeba to mieć!"
                },
                {
                    "en": "Każda książka jest interesująca.",
                    "ua": "jest — liczba pojedyncza"
                }
            ],
            "note": "📌 Każda zawsze + liczba pojedyncza (jest, ma, robi)."
        },
        {
            "label": "Każdy z + liczba mnoga rzeczownik",
            "color": "purple",
            "description": "Możesz użyć <strong>każdego z + the/this/those + rzeczownika w liczbie mnogiej</strong>. Czasownik jest w liczbie pojedynczej!",
            "examples": [
                {
                    "en": "Każdy z uczniów ma książkę.",
                    "ua": "Każdy z uczniów ma książkę."
                },
                {
                    "en": "Każda z tych książek jest dobra.",
                    "ua": "Każda z tych książek jest dobrze."
                }
            ],
            "note": "Każdy z + liczba mnoga, ale czasownik w liczbie pojedynczej!"
        }
    ]
}

{
    "title": "3. KAŻDY – wszyscy bez wyjątku",
    "sections": [
        {
            "label": "Każdy = jako grupa",
            "color": "blue",
            "description": "<strong>Każdy</strong> oznacza „wszyscy bez wyjątku” – skup się na grupie jako całości, na wszystkich bez wyjątku.",
            "examples": [
                {
                    "en": "Każdy uczeń zdał egzamin.",
                    "ua": "Każdy uczeń zdał egzamin (wszyscy razem, bez wyjątek)."
                },
                {
                    "en": "Każdego dnia idę do pracy.",
                    "ua": "Każdego dnia idę do pracy."
                },
                {
                    "en": "Każdy człowiek potrzebuje jedzenia.",
                    "ua": "Każdy człowiek potrzebuje jedzenia (ogólnie każdy)."
                }
            ]
        },
        {
            "label": "Każdy + liczba pojedyncza",
            "color": "sky",
            "description": "<strong>Every</strong> zawsze występuje z <strong>rzeczownikiem i czasownikiem w liczbie pojedynczej</strong>.",
            "examples": [
                {
                    "en": "Każdy uczeń jest... (✓)",
                    "ua": "jest - liczba pojedyncza"
                },
                {
                    "en": "Każdy uczeń jest... (✗)",
                    "ua": "BŁĄD - musi być!"
                },
                {
                    "en": "Każde dziecko potrzebuje miłości.",
                    "ua": "potrzeby - liczba pojedyncza"
                }
            ],
            "note": "📌 Zawsze + liczba pojedyncza (jest, ma, robi)."
        },
        {
            "label": "Za każdym razem + wyrażenia",
            "color": "purple",
            "description": "<strong>Every</strong> jest często używane z wyrażeniami czasu.",
            "examples": [
                {
                    "en": "codziennie, co tydzień, co miesiąc, co rok",
                    "ua": "codziennie, co tydzień, co miesiąc, co rok"
                },
                {
                    "en": "ćwiczę co dziennie.",
                    "ua": "Ćwiczę codziennie."
                },
                {
                    "en": "Spotykamy się w każdy piątek.",
                    "ua": "w każdy piątek."
                }
            ],
            "note": "Codziennie = codziennie, co tydzień (regularnie)."
        },
        {
            "label": "NIE możliwe: co tydzień z ",
            "color": "rose",
            "description": "Nie ma ŻADNEJ konstrukcji <strong>każdego z</strong>! Użyj każdego lub wszystkich.",
            "examples": [
                {
                    "en": "Każdy z uczniów... (✗)",
                    "ua": "BŁĄD - tak nie mówią!"
                },
                {
                    "en": "Każdy z uczniów... (✓)",
                    "ua": "Poprawnie - każdy z"
                },
                {
                    "en": "Wszyscy uczniowie... (✓)",
                    "ua": "Poprawnie – wszyscy z"
                }
            ],
            "note": "📌 Nie ma „każdego z”! Tylko każdy lub wszystkie."
        }
    ]
}

{
    "title": "4. WSZYSCY – wszyscy razem",
    "sections": [
        {
            "label": "Wszystkie = ogólność",
            "color": "amber",
            "description": "<strong>Wszystkie</strong> oznacza „wszystko” lub „wszystko” — skup się na ogólności, na wszystkich razem.",
            "examples": [
                {
                    "en": "Wszyscy uczniowie są tutaj.",
                    "ua": "Wszyscy uczniowie są tutaj (wszyscy) razem)."
                },
                {
                    "en": "Wszyscy ludzie potrzebują miłości.",
                    "ua": "Wszyscy ludzie potrzebują miłości."
                },
                {
                    "en": "I ate all the cookies.",
                    "ua": "Я з'їв усі печива."
                }
            ]
        },
        {
            "label": "All + plural",
            "color": "sky",
            "description": "<strong>All</strong> зазвичай з <strong>іменником і дієсловом у множині</strong>.",
            "examples": [
                {
                    "en": "All students are... (✓)",
                    "ua": "are - liczba mnoga"
                },
                {
                    "en": "Wszyscy uczniowie są... (✗)",
                    "ua": "BŁĄD - musi być!"
                },
                {
                    "en": "Wszystkie książki są interesujące.",
                    "ua": "are - liczba mnoga"
                }
            ],
            "note": "📌 All (liczba mnoga) + czasownik w liczbie mnogiej (are, have, do)."
        },
        {
            "label": "All + uncountable",
            "color": "purple",
            "description": "<strong>All</strong> jest również używane z rzeczownikami niepoliczalnymi (czasownik w liczbie pojedynczej).",
            "examples": [
                {
                    "en": "Cała woda to ważne.",
                    "ua": "Każda woda jest ważna."
                },
                {
                    "en": "Wszystkie informacje są poprawne.",
                    "ua": "Wszystkie informacje są poprawne."
                }
            ],
            "note": "Wszystkie + niepoliczalne → czasownik w liczbie pojedynczej."
        },
        {
            "label": "Wszystkie + the/tes/my",
            "color": "emerald",
            "description": "W przypadku artykułu, słów wskazujących lub zaborczych używamy <strong>wszystkich</strong>.",
            "examples": [
                {
                    "en": "Wszyscy uczniowie są, wszystkie te książki są moje. te/te/te/moje/twoje.",
                    "ua": "Усі студенти тут."
                },
                {
                    "en": "All of these books are mine.",
                    "ua": "Усі ці книги мої."
                },
                {
                    "en": "All of my friends came.",
                    "ua": "Усі мої друзі прийшли."
                }
            ],
            "note": "📌 All of + the/these/those/my/your."
        }
    ]
}

{
    "title": "5. Każdy kontra każdy – kiedy użyć słowa <strong>Każdy</strong> – gdy rozpatrywać go jako grupę.",
    "sections": [
        {
            "label": "Акцент: індивідуальність vs група",
            "color": "emerald",
            "description": "<strong>Each</strong> — коли важлива індивідуальність кожного. <strong>Every</strong> — коли розглядаємо як групу.",
            "examples": [
                {
                    "en": "Każdy uczeń ma inne potrzeby. (indywidualnie)",
                    "ua": "Każdy uczeń ma inne potrzeby."
                },
                {
                    "en": "Każdy student musi zdać egzamin. (wszyscy jako grupa)",
                    "ua": "Każdy uczeń musi przystąpić do egzaminu."
                }
            ]
        },
        {
            "label": "Każdy - dla małych grup",
            "color": "blue",
            "description": "<strong>Każdy</strong> częściej dla małych grup (2-10). Każdy jest na dowolny rozmiar. (duża grupa)",
            "examples": [
                {
                    "en": "Each of my three cats... (мала група)",
                    "ua": "Кожен з моїх трьох котів... (each краще для 2-3 елементів)"
                },
                {
                    "en": "Every citizen has rights. (велика група)",
                    "ua": "Każdy obywatel ma prawa (każdy w przypadku dużych grup)"
                }
            ],
            "note": "Każdy = małe grupy. Every = dowolny rozmiar."
        },
        {
            "label": "Każdy może występować po rzeczowniku",
            "color": "sky",
            "description": "<strong>Każdy</strong> może występować po rzeczowniku. <strong>Każdy</strong> – tylko wcześniej.",
            "examples": [
                {
                    "en": "Każdy uczeń ma swoją książkę. (✓)",
                    "ua": "każdy po rzeczowniku"
                },
                {
                    "en": "Każdy z uczniów ma książkę. (✗)",
                    "ua": "każdy nie może po!"
                }
            ],
            "note": "📌 Każdy może po rzeczowniku. Co - tylko wcześniej."
        }
    ]
}

{
    "title": "6. Każdy vs Wszyscy – kiedy używać",
    "sections": [
        {
            "label": "Każdy + liczba pojedyncza, Wszystko + liczba mnoga",
            "color": "amber",
            "description": "Główna różnica: <strong>każdy + liczba pojedyncza</strong>, <strong>wszystko + liczba mnoga</strong>.",
            "examples": [
                {
                    "en": "Każdy uczeń jest... (liczba pojedyncza)",
                    "ua": "Każdy student..."
                },
                {
                    "en": "Wszyscy uczniowie są... (liczba mnoga)",
                    "ua": "Wszyscy uczniowie..."
                }
            ]
        },
        {
            "label": "Wszyscy – gdy istnieje konkretna grupa",
            "color": "blue",
            "description": "<strong>Wszyscy</strong> – gdy mówimy o konkretnej, określonej grupie.",
            "examples": [
                {
                    "en": "Wszyscy uczniowie w moich zajęciach zaliczyło.",
                    "ua": "Wszyscy uczniowie w mojej klasie zaliczyli (konkretna grupa)."
                },
                {
                    "en": "Każdy uczeń musi się uczyć. (ogólnie)",
                    "ua": "Każdy uczeń powinien się uczyć (ogólna zasada)."
                }
            ],
            "note": "Wszyscy = konkretna grupa. Każdy = ogólna zasada."
        },
        {
            "label": "Wszystkie mogą być niezależne",
            "color": "sky",
            "description": "<strong>Wszystkie</strong> mogą występować samodzielnie, bez rzeczownika. <strong>Każdy</strong> – nie.",
            "examples": [
                {
                    "en": "Wszyscy są mile widziani. (✓)",
                    "ua": "Wszyscy są mile widziani."
                },
                {
                    "en": "Wszyscy są mile widziani. (✗)",
                    "ua": "BŁĄD — każdy potrzebuje rzeczownika!"
                }
            ],
            "note": "📌 Każdy może to zrobić niezależnie. Każdy - tylko + rzeczownik."
        }
    ]
}

{
    "title": "7. Pozycja w zdaniu",
    "sections": [
        {
            "label": "Każda pozycja jest elastyczna",
            "color": "emerald",
            "description": "<strong>Każda</strong> może znajdować się: przed rzeczownikiem, po rzeczowniku lub na końcu.",
            "examples": [
                {
                    "en": "Każdy uczeń ma książkę.",
                    "ua": "przed rzeczownikiem rzeczownik"
                },
                {
                    "en": "Każdy z uczniów ma książkę.",
                    "ua": "po rzeczowniku"
                },
                {
                    "en": "Kosztują 5 USD za sztukę.",
                    "ua": "na końcu (5 USD za sztukę)"
                }
            ]
        },
        {
            "label": "Każdy - tylko przed rzeczownik",
            "color": "blue",
            "description": "<strong>Every</strong> jest zawsze <strong>tylko przed rzeczownikiem</strong>.",
            "examples": [
                {
                    "en": "Każdy uczeń ma książkę. (✓)",
                    "ua": "przed rzeczownikiem"
                },
                {
                    "en": "Uczniowie mają... (✗)",
                    "ua": "BŁĄD"
                }
            ]
        },
        {
            "label": "Wszystkie — przed lub z ",
            "color": "amber",
            "description": "<strong>Wszystkie</strong> mogą: przed rzeczownikiem (bez przedimka) lub wszyscy z + artykułu/posiadacza.",
            "examples": [
                {
                    "en": "Wszyscy uczniowie... (bez przedimka)",
                    "ua": "Wszyscy uczniowie..."
                },
                {
                    "en": "Wszyscy uczniowie... (z artykułem)",
                    "ua": "Wszyscy uczniowie..."
                }
            ]
        }
    ]
}

{
    "title": "8. Typowe błędy osób mówiących po ukraińsku",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Czasownik w liczbie mnogiej z each/every.",
            "wrong": "Każdy uczeń jest... / Każda osoba ma...",
            "right": "​​​​ <span class="font-mono">Każdy uczeń jest... / Każda osoba ma...</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Użycie „każdy z”.",
            "wrong": "Każdy uczeń zdał.",
            "right": "​​​​ <span class="font-mono">Każdy uczeń zdał. Wszyscy uczniowie zdali. 4"
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Дієслово в однині з all + plural.",
            "wrong": "All students is here.",
            "right": "✅ <span class="font-mono">All students are here.</span>"
        },
        {
            "label": "Помилка 4",
            "color": "purple",
            "title": "Każdy po rzeczowniku.",
            "wrong": "Każdy uczeń ma książki.",
            "right": "​​​​ <span class="font-mono">Każdy uczeń ma książkę. / Każdy z uczniów ma książkę.</span>"
        }
    ]
}

{
    "title": "10. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwe słowo",
    "select_intro": "Wypełnij puste miejsca każdym, każdym lub wszystkimi.",
    "selects": [
        {
            "label": "___ uczeń ma książkę. (każdy / każdy / wszyscy)",
            "prompt": "Jakie słowo?"
        },
        {
            "label": "___ studenci są tutaj. (każdy / każdy / wszyscy)",
            "prompt": "Jakie słowo?"
        },
        {
            "label": "Widzę go ___ dzień. (każdy / każdy / wszyscy)",
            "prompt": "Jakie słowo?"
        },
        {
            "label": "___ z książek jest interesujące. (każdy / każdy / wszyscy)",
            "prompt": "Jakie słowo?"
        },
        {
            "label": "___ uczniów zdało egzamin. (każdy / każdy / wszyscy)",
            "prompt": "Jakie słowo?"
        }
    ],
    "options": [
        "każdy",
        "każdy",
        "wszyscy"
    ],
    "input_title": "Ćwiczenie 2. Wypełnij spacje",
    "input_intro": "Wpisz każde, każde lub wszystkie.",
    "inputs": [
        {
            "before": "___ osoba jest inna. (każda osoba z osobna)",
            "after": "→"
        },
        {
            "before": "___ ludzie potrzebują miłości. (wszyscy ludzie)",
            "after": " →"
        },
        {
            "before": "Ćwiczę ___ rano. (każdego ranka)",
            "after": "→"
        },
        {
            "before": "Kosztują 10 USD ___. (10 USD za sztukę)",
            "after": "→"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw błąd w każdym, każdym lub wszystkich.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Każdy uczeń jest tutaj.",
            "example_target": "Każdy uczeń jest tutaj."
        },
        {
            "original": "1. Każda książka jest dobra.",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. Wszyscy uczniowie są gotowi.",
            "placeholder": "Popraw błąd"
        },
        {
            "original": "3. Wszyscy uczniowie mają książki.",
            "placeholder": "Popraw błąd"
        }
    ]
}

